package strategy

import (
	"context"
	"errors"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strings"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/agent"
	cpkg "github.com/entireio/cli/cmd/entire/cli/checkpoint"
	"github.com/entireio/cli/cmd/entire/cli/checkpoint/id"
	"github.com/entireio/cli/cmd/entire/cli/paths"
	"github.com/entireio/cli/cmd/entire/cli/trailers"

	"github.com/charmbracelet/huh"
	"github.com/go-git/go-git/v5"
	"github.com/go-git/go-git/v5/plumbing"
	"github.com/go-git/go-git/v5/plumbing/filemode"
	"github.com/go-git/go-git/v5/plumbing/object"
)

// GetRewindPoints returns available rewind points.
// Uses checkpoint.GitStore.ListTemporaryCheckpoints for reading from shadow branches.
func (s *ManualCommitStrategy) GetRewindPoints(limit int) ([]RewindPoint, error) {
	repo, err := OpenRepository()
	if err != nil {
		return nil, fmt.Errorf("failed to open git repository: %w", err)
	}

	// Get checkpoint store
	store, err := s.getCheckpointStore()
	if err != nil {
		return nil, fmt.Errorf("failed to get checkpoint store: %w", err)
	}

	// Get current HEAD to find matching shadow branch
	head, err := repo.Head()
	if err != nil {
		return nil, fmt.Errorf("failed to get HEAD: %w", err)
	}

	// Find sessions for current HEAD
	sessions, err := s.findSessionsForCommit(head.Hash().String())
	if err != nil {
		// Log error but continue to check for logs-only points
		sessions = nil
	}

	var allPoints []RewindPoint

	// Collect checkpoint points from active sessions using checkpoint.GitStore
	// Cache session prompts by session ID to avoid re-reading the same prompt file
	sessionPrompts := make(map[string]string)

	for _, state := range sessions {
		checkpoints, err := store.ListTemporaryCheckpoints(context.Background(), state.BaseCommit, state.WorktreeID, state.SessionID, limit)
		if err != nil {
			continue // Error reading checkpoints, skip this session
		}

		for _, cp := range checkpoints {
			// Get session prompt (cached by session ID)
			sessionPrompt, ok := sessionPrompts[cp.SessionID]
			if !ok {
				sessionPrompt = readSessionPrompt(repo, cp.CommitHash, cp.MetadataDir)
				sessionPrompts[cp.SessionID] = sessionPrompt
			}

			allPoints = append(allPoints, RewindPoint{
				ID:               cp.CommitHash.String(),
				Message:          cp.Message,
				MetadataDir:      cp.MetadataDir,
				Date:             cp.Timestamp,
				IsTaskCheckpoint: cp.IsTaskCheckpoint,
				ToolUseID:        cp.ToolUseID,
				SessionID:        cp.SessionID,
				SessionPrompt:    sessionPrompt,
				Agent:            state.AgentType,
			})
		}
	}

	// Sort by date, most recent first
	sort.Slice(allPoints, func(i, j int) bool {
		return allPoints[i].Date.After(allPoints[j].Date)
	})

	if len(allPoints) > limit {
		allPoints = allPoints[:limit]
	}

	// Also include logs-only points from commit history
	logsOnlyPoints, err := s.GetLogsOnlyRewindPoints(limit)
	if err == nil && len(logsOnlyPoints) > 0 {
		// Build set of existing point IDs for deduplication
		existingIDs := make(map[string]bool)
		for _, p := range allPoints {
			existingIDs[p.ID] = true
		}

		// Add logs-only points that aren't already in the list
		for _, p := range logsOnlyPoints {
			if !existingIDs[p.ID] {
				allPoints = append(allPoints, p)
			}
		}

		// Re-sort by date
		sort.Slice(allPoints, func(i, j int) bool {
			return allPoints[i].Date.After(allPoints[j].Date)
		})

		// Re-trim to limit
		if len(allPoints) > limit {
			allPoints = allPoints[:limit]
		}
	}

	return allPoints, nil
}

// GetLogsOnlyRewindPoints finds commits in the current branch's history that have
// condensed session logs on the entire/checkpoints/v1 branch. These are commits that
// were created with session data but the shadow branch has been condensed.
//
// The function works by:
// 1. Getting all checkpoints from the entire/checkpoints/v1 branch
// 2. Building a map of checkpoint ID -> checkpoint info
// 3. Scanning the current branch history for commits with Entire-Checkpoint trailers
// 4. Matching by checkpoint ID (stable across amend/rebase)
func (s *ManualCommitStrategy) GetLogsOnlyRewindPoints(limit int) ([]RewindPoint, error) {
	repo, err := OpenRepository()
	if err != nil {
		return nil, err
	}

	// Get all checkpoints from entire/checkpoints/v1 branch
	checkpoints, err := s.listCheckpoints()
	if err != nil {
		// No checkpoints yet is fine
		return nil, nil //nolint:nilerr // Expected when no checkpoints exist
	}

	if len(checkpoints) == 0 {
		return nil, nil
	}

	// Build map of checkpoint ID -> checkpoint info
	// Checkpoint ID is the stable link from Entire-Checkpoint trailer
	checkpointInfoMap := make(map[id.CheckpointID]CheckpointInfo)
	for _, cp := range checkpoints {
		if !cp.CheckpointID.IsEmpty() {
			checkpointInfoMap[cp.CheckpointID] = cp
		}
	}

	// Get metadata branch tree for reading session prompts (best-effort, ignore errors)
	metadataTree, _ := GetMetadataBranchTree(repo) //nolint:errcheck // Best-effort for session prompts

	head, err := repo.Head()
	if err != nil {
		return nil, fmt.Errorf("failed to get HEAD: %w", err)
	}

	// Use LogOptions with Order=LogOrderCommitterTime to traverse all parents of merge commits.
	iter, err := repo.Log(&git.LogOptions{
		From:  head.Hash(),
		Order: git.LogOrderCommitterTime,
	})
	if err != nil {
		return nil, fmt.Errorf("failed to get commit log: %w", err)
	}

	var points []RewindPoint
	count := 0

	err = iter.ForEach(func(c *object.Commit) error {
		if count >= logsOnlyScanLimit {
			return errStop
		}
		count++

		// Extract checkpoint ID from Entire-Checkpoint trailer (ParseCheckpoint validates format)
		cpID, found := trailers.ParseCheckpoint(c.Message)
		if !found {
			return nil
		}
		// Check if this checkpoint ID has metadata on entire/checkpoints/v1
		cpInfo, found := checkpointInfoMap[cpID]
		if !found {
			return nil
		}

		// Create logs-only rewind point
		message := strings.Split(c.Message, "\n")[0]

		// Read session prompts from metadata tree
		var sessionPrompt string
		var sessionPrompts []string
		if metadataTree != nil {
			checkpointPath := paths.CheckpointPath(cpInfo.CheckpointID) //nolint:staticcheck // already present in codebase
			// For multi-session checkpoints, read all prompts
			if cpInfo.SessionCount > 1 && len(cpInfo.SessionIDs) > 1 {
				sessionPrompts = ReadAllSessionPromptsFromTree(metadataTree, checkpointPath, cpInfo.SessionCount, cpInfo.SessionIDs)
				// Use the last (most recent) prompt as the main session prompt
				if len(sessionPrompts) > 0 {
					sessionPrompt = sessionPrompts[len(sessionPrompts)-1]
				}
			} else {
				sessionPrompt = ReadSessionPromptFromTree(metadataTree, checkpointPath)
				if sessionPrompt != "" {
					sessionPrompts = []string{sessionPrompt}
				}
			}
		}

		points = append(points, RewindPoint{
			ID:             c.Hash.String(),
			Message:        message,
			Date:           c.Author.When,
			IsLogsOnly:     true,
			CheckpointID:   cpInfo.CheckpointID,
			Agent:          cpInfo.Agent,
			SessionID:      cpInfo.SessionID,
			SessionPrompt:  sessionPrompt,
			SessionCount:   cpInfo.SessionCount,
			SessionIDs:     cpInfo.SessionIDs,
			SessionPrompts: sessionPrompts,
		})

		return nil
	})

	if err != nil && !errors.Is(err, errStop) {
		return nil, fmt.Errorf("error iterating commits: %w", err)
	}

	if len(points) > limit {
		points = points[:limit]
	}

	return points, nil
}

// Rewind restores the working directory to a checkpoint.
//

func (s *ManualCommitStrategy) Rewind(point RewindPoint) error {
	repo, err := OpenRepository()
	if err != nil {
		return fmt.Errorf("failed to open git repository: %w", err)
	}

	// Get the checkpoint commit
	commitHash := plumbing.NewHash(point.ID)
	commit, err := repo.CommitObject(commitHash)
	if err != nil {
		return fmt.Errorf("failed to get commit: %w", err)
	}

	tree, err := commit.Tree()
	if err != nil {
		return fmt.Errorf("failed to get tree: %w", err)
	}

	// Reset the shadow branch to the rewound checkpoint
	// This ensures the next checkpoint will only include prompts from this point forward
	if err := s.resetShadowBranchToCheckpoint(repo, commit); err != nil {
		// Log warning but don't fail - file restoration is the primary operation
		fmt.Fprintf(os.Stderr, "[entire] Warning: failed to reset shadow branch: %v\n", err)
	}

	// Load session state to get untracked files that existed at session start
	sessionID, hasSessionTrailer := trailers.ParseSession(commit.Message)
	var preservedUntrackedFiles map[string]bool
	if hasSessionTrailer {
		state, stateErr := s.loadSessionState(sessionID)
		if stateErr == nil && state != nil && len(state.UntrackedFilesAtStart) > 0 {
			preservedUntrackedFiles = make(map[string]bool)
			for _, f := range state.UntrackedFilesAtStart {
				preservedUntrackedFiles[f] = true
			}
		}
	}

	// Build set of files in the checkpoint tree (excluding metadata)
	checkpointFiles := make(map[string]bool)
	err = tree.Files().ForEach(func(f *object.File) error {
		if !strings.HasPrefix(f.Name, entireDir) {
			checkpointFiles[f.Name] = true
		}
		return nil
	})
	if err != nil {
		return fmt.Errorf("failed to list checkpoint files: %w", err)
	}

	// Get HEAD tree to identify tracked files
	head, err := repo.Head()
	if err != nil {
		return fmt.Errorf("failed to get HEAD: %w", err)
	}
	headCommit, err := repo.CommitObject(head.Hash())
	if err != nil {
		return fmt.Errorf("failed to get HEAD commit: %w", err)
	}
	headTree, err := headCommit.Tree()
	if err != nil {
		return fmt.Errorf("failed to get HEAD tree: %w", err)
	}

	// Build set of files tracked in HEAD
	trackedFiles := make(map[string]bool)
	//nolint:errcheck // Error is not critical for rewind
	_ = headTree.Files().ForEach(func(f *object.File) error {
		trackedFiles[f.Name] = true
		return nil
	})

	// Get repository root to walk from there
	repoRoot, err := GetWorktreePath()
	if err != nil {
		repoRoot = "." // Fallback to current directory
	}

	// Find and delete untracked files that aren't in the checkpoint
	// These are likely files created by the agent in later checkpoints
	err = filepath.Walk(repoRoot, func(path string, info os.FileInfo, walkErr error) error {
		if walkErr != nil {
			return nil //nolint:nilerr // Skip filesystem errors during walk
		}

		// Get path relative to repo root
		relPath, relErr := filepath.Rel(repoRoot, path)
		if relErr != nil {
			return nil //nolint:nilerr // Skip paths we can't make relative
		}

		// Skip directories and protected paths
		if info.IsDir() {
			if isProtectedPath(relPath) {
				return filepath.SkipDir
			}
			return nil
		}

		// Skip files in protected directories
		if isProtectedPath(relPath) {
			return nil
		}

		// If file is in checkpoint, it will be restored
		if checkpointFiles[relPath] {
			return nil
		}

		// If file is tracked in HEAD, don't delete (user's committed work)
		if trackedFiles[relPath] {
			return nil
		}

		// If file existed at session start, preserve it (untracked user files)
		if preservedUntrackedFiles[relPath] {
			return nil
		}

		// File is untracked and not in checkpoint - delete it (use absolute path)
		if removeErr := os.Remove(path); removeErr == nil {
			fmt.Fprintf(os.Stderr, "  Deleted: %s\n", relPath)
		}

		return nil
	})
	if err != nil {
		// Non-fatal - continue with restoration
		fmt.Fprintf(os.Stderr, "Warning: error walking directory: %v\n", err)
	}

	// Restore files from checkpoint
	err = tree.Files().ForEach(func(f *object.File) error {
		// Skip metadata directories - these are for checkpoint storage, not working dir
		if strings.HasPrefix(f.Name, entireDir) {
			return nil
		}

		contents, err := f.Contents()
		if err != nil {
			return fmt.Errorf("failed to read file %s: %w", f.Name, err)
		}

		// Ensure directory exists
		dir := filepath.Dir(f.Name)
		if dir != "." {
			//nolint:gosec // G301: Need 0o755 for user directories during rewind
			if err := os.MkdirAll(dir, 0o755); err != nil {
				return fmt.Errorf("failed to create directory %s: %w", dir, err)
			}
		}

		// Write file with appropriate permissions
		var perm os.FileMode = 0o644
		if f.Mode == filemode.Executable {
			perm = 0o755
		}
		if err := os.WriteFile(f.Name, []byte(contents), perm); err != nil {
			return fmt.Errorf("failed to write file %s: %w", f.Name, err)
		}

		fmt.Fprintf(os.Stderr, "  Restored: %s\n", f.Name)
		return nil
	})
	if err != nil {
		return fmt.Errorf("failed to iterate tree files: %w", err)
	}

	fmt.Println()
	if len(point.ID) >= 7 {
		fmt.Printf("Restored files from shadow commit %s\n", point.ID[:7])
	} else {
		fmt.Printf("Restored files from shadow commit %s\n", point.ID)
	}
	fmt.Println()

	return nil
}

// resetShadowBranchToCheckpoint resets the shadow branch HEAD to the given checkpoint.
// This ensures that when the user commits after rewinding, the next checkpoint will only
// include prompts from the rewound point, not prompts from later checkpoints.
func (s *ManualCommitStrategy) resetShadowBranchToCheckpoint(repo *git.Repository, commit *object.Commit) error {
	// Extract session ID from the checkpoint commit's Entire-Session trailer
	sessionID, found := trailers.ParseSession(commit.Message)
	if !found {
		return errors.New("checkpoint has no Entire-Session trailer")
	}

	// Load session state to get the shadow branch name
	state, err := s.loadSessionState(sessionID)
	if err != nil {
		return fmt.Errorf("failed to load session state: %w", err)
	}
	if state == nil {
		return fmt.Errorf("session %s not found", sessionID)
	}

	// Reset the shadow branch to the checkpoint commit
	shadowBranchName := getShadowBranchNameForCommit(state.BaseCommit, state.WorktreeID)
	refName := plumbing.NewBranchReferenceName(shadowBranchName)

	// Update the reference to point to the checkpoint commit
	ref := plumbing.NewHashReference(refName, commit.Hash)
	if err := repo.Storer.SetReference(ref); err != nil {
		return fmt.Errorf("failed to update shadow branch: %w", err)
	}

	fmt.Fprintf(os.Stderr, "[entire] Reset shadow branch %s to checkpoint %s\n", shadowBranchName, commit.Hash.String()[:7])
	return nil
}

// CanRewind checks if rewinding is possible.
// For manual-commit strategy, rewind restores files from a checkpoint - uncommitted changes are expected
// and will be replaced by the checkpoint contents. Returns true with a warning message showing
// what changes will be reverted.
func (s *ManualCommitStrategy) CanRewind() (bool, string, error) {
	return checkCanRewindWithWarning()
}

// PreviewRewind returns what will happen if rewinding to the given point.
// This allows showing warnings about untracked files that will be deleted.
func (s *ManualCommitStrategy) PreviewRewind(point RewindPoint) (*RewindPreview, error) {
	// Logs-only points don't modify the working directory
	if point.IsLogsOnly {
		return &RewindPreview{}, nil
	}

	repo, err := OpenRepository()
	if err != nil {
		return nil, fmt.Errorf("failed to open git repository: %w", err)
	}

	// Get the checkpoint commit
	commitHash := plumbing.NewHash(point.ID)
	commit, err := repo.CommitObject(commitHash)
	if err != nil {
		return nil, fmt.Errorf("failed to get commit: %w", err)
	}

	tree, err := commit.Tree()
	if err != nil {
		return nil, fmt.Errorf("failed to get tree: %w", err)
	}

	// Load session state to get untracked files that existed at session start
	sessionID, hasSessionTrailer := trailers.ParseSession(commit.Message)
	var preservedUntrackedFiles map[string]bool
	if hasSessionTrailer {
		state, stateErr := s.loadSessionState(sessionID)
		if stateErr == nil && state != nil && len(state.UntrackedFilesAtStart) > 0 {
			preservedUntrackedFiles = make(map[string]bool)
			for _, f := range state.UntrackedFilesAtStart {
				preservedUntrackedFiles[f] = true
			}
		}
	}

	// Build set of files in the checkpoint tree (excluding metadata)
	checkpointFiles := make(map[string]bool)
	var filesToRestore []string
	err = tree.Files().ForEach(func(f *object.File) error {
		if !strings.HasPrefix(f.Name, entireDir) {
			checkpointFiles[f.Name] = true
			filesToRestore = append(filesToRestore, f.Name)
		}
		return nil
	})
	if err != nil {
		return nil, fmt.Errorf("failed to list checkpoint files: %w", err)
	}

	// Get HEAD tree to identify tracked files
	head, err := repo.Head()
	if err != nil {
		return nil, fmt.Errorf("failed to get HEAD: %w", err)
	}
	headCommit, err := repo.CommitObject(head.Hash())
	if err != nil {
		return nil, fmt.Errorf("failed to get HEAD commit: %w", err)
	}
	headTree, err := headCommit.Tree()
	if err != nil {
		return nil, fmt.Errorf("failed to get HEAD tree: %w", err)
	}

	// Build set of files tracked in HEAD
	trackedFiles := make(map[string]bool)
	//nolint:errcheck // Error is not critical for preview
	_ = headTree.Files().ForEach(func(f *object.File) error {
		trackedFiles[f.Name] = true
		return nil
	})

	// Get repository root to walk from there
	repoRoot, err := GetWorktreePath()
	if err != nil {
		repoRoot = "."
	}

	// Find untracked files that would be deleted
	var filesToDelete []string
	err = filepath.Walk(repoRoot, func(path string, info os.FileInfo, walkErr error) error {
		if walkErr != nil {
			return nil //nolint:nilerr // Skip filesystem errors during walk
		}

		relPath, relErr := filepath.Rel(repoRoot, path)
		if relErr != nil {
			return nil //nolint:nilerr // Skip paths we can't make relative
		}

		// Skip directories and protected paths
		if info.IsDir() {
			if isProtectedPath(relPath) {
				return filepath.SkipDir
			}
			return nil
		}

		// Skip files in protected directories
		if isProtectedPath(relPath) {
			return nil
		}

		// If file is in checkpoint, it will be restored (not deleted)
		if checkpointFiles[relPath] {
			return nil
		}

		// If file is tracked in HEAD, don't delete (user's committed work)
		if trackedFiles[relPath] {
			return nil
		}

		// If file existed at session start, preserve it (untracked user files)
		if preservedUntrackedFiles[relPath] {
			return nil
		}

		// File is untracked and not in checkpoint - will be deleted
		filesToDelete = append(filesToDelete, relPath)
		return nil
	})
	if err != nil {
		// Non-fatal, return what we have
		return &RewindPreview{ //nolint:nilerr // Partial result is still useful
			FilesToRestore: filesToRestore,
			FilesToDelete:  filesToDelete,
		}, nil
	}

	// Sort for consistent output
	sort.Strings(filesToRestore)
	sort.Strings(filesToDelete)

	return &RewindPreview{
		FilesToRestore: filesToRestore,
		FilesToDelete:  filesToDelete,
	}, nil
}

// RestoreLogsOnly restores session logs from a logs-only rewind point.
// This fetches the transcript from entire/checkpoints/v1 and writes it to the agent's session directory.
// Does not modify the working directory.
// When multiple sessions were condensed to the same checkpoint, ALL sessions are restored.
// If force is false, prompts for confirmation when local logs have newer timestamps.
// Returns info about each restored session so callers can print correct per-session resume commands.
func (s *ManualCommitStrategy) RestoreLogsOnly(point RewindPoint, force bool) ([]RestoredSession, error) {
	if !point.IsLogsOnly {
		return nil, errors.New("not a logs-only rewind point")
	}

	if point.CheckpointID.IsEmpty() {
		return nil, errors.New("missing checkpoint ID")
	}

	// Get checkpoint store
	store, err := s.getCheckpointStore()
	if err != nil {
		return nil, fmt.Errorf("failed to get checkpoint store: %w", err)
	}

	// Read checkpoint summary to get session count
	summary, err := store.ReadCommitted(context.Background(), point.CheckpointID)
	if err != nil {
		return nil, fmt.Errorf("failed to read checkpoint: %w", err)
	}
	if summary == nil {
		return nil, fmt.Errorf("checkpoint not found: %s", point.CheckpointID)
	}

	// Get repo root for agent session directory lookup
	repoRoot, err := paths.RepoRoot()
	if err != nil {
		return nil, fmt.Errorf("failed to get repository root: %w", err)
	}

	// Check for newer local logs if not forcing
	if !force {
		sessions := s.classifySessionsForRestore(context.Background(), repoRoot, store, point.CheckpointID, summary)
		hasConflicts := false
		for _, sess := range sessions {
			if sess.Status == StatusLocalNewer {
				hasConflicts = true
				break
			}
		}
		if hasConflicts {
			shouldOverwrite, promptErr := PromptOverwriteNewerLogs(sessions)
			if promptErr != nil {
				return nil, promptErr
			}
			if !shouldOverwrite {
				fmt.Fprintf(os.Stderr, "Resume cancelled. Local session logs preserved.\n")
				return nil, nil
			}
		}
	}

	// Count sessions to restore
	totalSessions := len(summary.Sessions)
	if totalSessions > 1 {
		fmt.Fprintf(os.Stderr, "Restoring %d sessions from checkpoint:\n", totalSessions)
	}

	// Restore all sessions (oldest to newest, using 0-based indexing)
	var restored []RestoredSession
	for i := range totalSessions {
		content, readErr := store.ReadSessionContent(context.Background(), point.CheckpointID, i)
		if readErr != nil {
			fmt.Fprintf(os.Stderr, "  Warning: failed to read session %d: %v\n", i, readErr)
			continue
		}
		if content == nil || len(content.Transcript) == 0 {
			continue
		}

		sessionID := content.Metadata.SessionID
		if sessionID == "" {
			fmt.Fprintf(os.Stderr, "  Warning: session %d has no session ID, skipping\n", i)
			continue
		}

		// Resolve per-session agent from metadata — skip if agent is unknown
		if content.Metadata.Agent == "" {
			fmt.Fprintf(os.Stderr, "  Warning: session %d (%s) has no agent metadata, skipping (cannot determine target directory)\n", i, sessionID)
			continue
		}
		sessionAgent, agErr := ResolveAgentForRewind(content.Metadata.Agent)
		if agErr != nil {
			fmt.Fprintf(os.Stderr, "  Warning: session %d (%s) has unknown agent %q, skipping\n", i, sessionID, content.Metadata.Agent)
			continue
		}

		// Prefer transcript path from checkpoint metadata (works for all agents).
		// Fall back to agent-based resolution for old checkpoints without this field.
		var sessionFile string
		if resolved := resolveTranscriptPathFromMetadata(content.Metadata.TranscriptPath); resolved != "" {
			sessionFile = resolved
		} else {
			sessionAgentDir, dirErr := sessionAgent.GetSessionDir(repoRoot)
			if dirErr != nil {
				fmt.Fprintf(os.Stderr, "  Warning: failed to get session dir for session %d: %v\n", i, dirErr)
				continue
			}
			sessionFile = ResolveSessionFilePath(sessionID, sessionAgent, sessionAgentDir)
		}

		// Get first prompt for display
		promptPreview := ExtractFirstPrompt(content.Prompts)

		if totalSessions > 1 {
			isLatest := i == totalSessions-1
			if promptPreview != "" {
				if isLatest {
					fmt.Fprintf(os.Stderr, "  Session %d (latest): %s\n", i+1, promptPreview)
				} else {
					fmt.Fprintf(os.Stderr, "  Session %d: %s\n", i+1, promptPreview)
				}
			}
			fmt.Fprintf(os.Stderr, "    Writing to: %s\n", sessionFile)
		} else {
			fmt.Fprintf(os.Stderr, "Writing transcript to: %s\n", sessionFile)
		}

		// Ensure parent directory exists (session file may be in a different dir than sessionAgentDir)
		if mkdirErr := os.MkdirAll(filepath.Dir(sessionFile), 0o750); mkdirErr != nil {
			fmt.Fprintf(os.Stderr, "    Warning: failed to create directory: %v\n", mkdirErr)
			continue
		}

		if writeErr := os.WriteFile(sessionFile, content.Transcript, 0o600); writeErr != nil {
			if totalSessions > 1 {
				fmt.Fprintf(os.Stderr, "    Warning: failed to write transcript: %v\n", writeErr)
				continue
			}
			return nil, fmt.Errorf("failed to write transcript: %w", writeErr)
		}

		restored = append(restored, RestoredSession{
			SessionID: sessionID,
			Agent:     sessionAgent.Type(),
			Prompt:    promptPreview,
		})
	}

	return restored, nil
}

// resolveTranscriptPathFromMetadata expands a home-relative transcript path
// from checkpoint metadata to an absolute path. Returns "" if the path is empty.
func resolveTranscriptPathFromMetadata(homeRelPath string) string {
	if homeRelPath == "" {
		return ""
	}
	home, err := os.UserHomeDir()
	if err != nil || home == "" {
		return ""
	}
	return filepath.Join(home, homeRelPath)
}

// ResolveAgentForRewind resolves the agent from checkpoint metadata.
// Falls back to the default agent (Claude) for old checkpoints that lack agent info.
func ResolveAgentForRewind(agentType agent.AgentType) (agent.Agent, error) {
	if !isSpecificAgentType(agentType) {
		ag := agent.Default()
		if ag == nil {
			return nil, errors.New("no default agent registered")
		}
		return ag, nil
	}
	ag, err := agent.GetByAgentType(agentType)
	if err != nil {
		return nil, fmt.Errorf("resolving agent %q: %w", agentType, err)
	}
	return ag, nil
}

// ResolveSessionFilePath determines the correct file path for an agent's session transcript.
// Checks session state for transcript_path first (needed for agents like Gemini that store
// transcripts at paths that GetSessionDir can't reconstruct, e.g. SHA-256 hashed directories).
// Falls back to the agent's ExtractAgentSessionID + ResolveSessionFile with fallbackSessionDir.
func ResolveSessionFilePath(sessionID string, ag agent.Agent, fallbackSessionDir string) string {
	state, err := LoadSessionState(sessionID)
	if err == nil && state != nil && state.TranscriptPath != "" {
		return state.TranscriptPath
	}

	return ag.ResolveSessionFile(fallbackSessionDir, sessionID)
}

// readSessionPrompt reads the first prompt from the session's prompt.txt file stored in git.
// Returns an empty string if the prompt cannot be read.
func readSessionPrompt(repo *git.Repository, commitHash plumbing.Hash, metadataDir string) string {
	// Get the commit and its tree
	commit, err := repo.CommitObject(commitHash)
	if err != nil {
		return ""
	}

	tree, err := commit.Tree()
	if err != nil {
		return ""
	}

	// Look for prompt.txt in the metadata directory
	promptPath := metadataDir + "/" + paths.PromptFileName
	promptEntry, err := tree.File(promptPath)
	if err != nil {
		return ""
	}

	content, err := promptEntry.Contents()
	if err != nil {
		return ""
	}

	return ExtractFirstPrompt(content)
}

// SessionRestoreStatus represents the status of a session being restored.
type SessionRestoreStatus int

const (
	StatusNew             SessionRestoreStatus = iota // Local file doesn't exist
	StatusUnchanged                                   // Local and checkpoint are the same
	StatusCheckpointNewer                             // Checkpoint has newer entries
	StatusLocalNewer                                  // Local has newer entries (conflict)
)

// SessionRestoreInfo contains information about a session being restored.
type SessionRestoreInfo struct {
	SessionID      string
	Prompt         string               // First prompt preview for display
	Status         SessionRestoreStatus // Status of this session
	LocalTime      time.Time
	CheckpointTime time.Time
}

// classifySessionsForRestore checks all sessions in a checkpoint and returns info
// about each session, including whether local logs have newer timestamps.
// repoRoot is used to compute per-session agent directories.
// Sessions without agent metadata are skipped (cannot determine target directory).
func (s *ManualCommitStrategy) classifySessionsForRestore(ctx context.Context, repoRoot string, store cpkg.Store, checkpointID id.CheckpointID, summary *cpkg.CheckpointSummary) []SessionRestoreInfo {
	var sessions []SessionRestoreInfo

	totalSessions := len(summary.Sessions)
	// Check all sessions (0-based indexing)
	for i := range totalSessions {
		content, err := store.ReadSessionContent(ctx, checkpointID, i)
		if err != nil || content == nil || len(content.Transcript) == 0 {
			continue
		}

		sessionID := content.Metadata.SessionID
		if sessionID == "" || content.Metadata.Agent == "" {
			continue
		}

		sessionAgent, agErr := ResolveAgentForRewind(content.Metadata.Agent)
		if agErr != nil {
			continue
		}

		// Prefer transcript path from checkpoint metadata, fall back to agent-based resolution.
		var localPath string
		if resolved := resolveTranscriptPathFromMetadata(content.Metadata.TranscriptPath); resolved != "" {
			localPath = resolved
		} else {
			sessionAgentDir, dirErr := sessionAgent.GetSessionDir(repoRoot)
			if dirErr != nil {
				continue
			}
			localPath = ResolveSessionFilePath(sessionID, sessionAgent, sessionAgentDir)
		}

		localTime := paths.GetLastTimestampFromFile(localPath)
		checkpointTime := paths.GetLastTimestampFromBytes(content.Transcript)
		status := ClassifyTimestamps(localTime, checkpointTime)

		sessions = append(sessions, SessionRestoreInfo{
			SessionID:      sessionID,
			Prompt:         ExtractFirstPrompt(content.Prompts),
			Status:         status,
			LocalTime:      localTime,
			CheckpointTime: checkpointTime,
		})
	}

	return sessions
}

// ClassifyTimestamps determines the restore status based on local and checkpoint timestamps.
func ClassifyTimestamps(localTime, checkpointTime time.Time) SessionRestoreStatus {
	// Local file doesn't exist (no timestamp found)
	if localTime.IsZero() {
		return StatusNew
	}

	// Can't determine checkpoint time - treat as new/safe
	if checkpointTime.IsZero() {
		return StatusNew
	}

	// Compare timestamps
	if localTime.After(checkpointTime) {
		return StatusLocalNewer
	}
	if checkpointTime.After(localTime) {
		return StatusCheckpointNewer
	}
	return StatusUnchanged
}

// StatusToText returns a human-readable status string.
func StatusToText(status SessionRestoreStatus) string {
	switch status {
	case StatusNew:
		return "(new)"
	case StatusUnchanged:
		return "(unchanged)"
	case StatusCheckpointNewer:
		return "(checkpoint is newer)"
	case StatusLocalNewer:
		return "(local is newer)" // shouldn't appear in non-conflict list
	default:
		return ""
	}
}

// PromptOverwriteNewerLogs asks the user for confirmation to overwrite local
// session logs that have newer timestamps than the checkpoint versions.
func PromptOverwriteNewerLogs(sessions []SessionRestoreInfo) (bool, error) {
	// Separate conflicting and non-conflicting sessions
	var conflicting, nonConflicting []SessionRestoreInfo
	for _, s := range sessions {
		if s.Status == StatusLocalNewer {
			conflicting = append(conflicting, s)
		} else {
			nonConflicting = append(nonConflicting, s)
		}
	}

	fmt.Fprintf(os.Stderr, "\nWarning: Local session log(s) have newer entries than the checkpoint:\n")
	for _, info := range conflicting {
		// Show prompt if available, otherwise fall back to session ID
		if info.Prompt != "" {
			fmt.Fprintf(os.Stderr, "  \"%s\"\n", info.Prompt)
		} else {
			fmt.Fprintf(os.Stderr, "  Session: %s\n", info.SessionID)
		}
		fmt.Fprintf(os.Stderr, "    Local last entry:      %s\n", info.LocalTime.Local().Format("2006-01-02 15:04:05"))
		fmt.Fprintf(os.Stderr, "    Checkpoint last entry: %s\n", info.CheckpointTime.Local().Format("2006-01-02 15:04:05"))
	}

	// Show non-conflicting sessions with their status
	if len(nonConflicting) > 0 {
		fmt.Fprintf(os.Stderr, "\nThese other session(s) will also be restored:\n")
		for _, info := range nonConflicting {
			statusText := StatusToText(info.Status)
			if info.Prompt != "" {
				fmt.Fprintf(os.Stderr, "  \"%s\" %s\n", info.Prompt, statusText)
			} else {
				fmt.Fprintf(os.Stderr, "  Session: %s %s\n", info.SessionID, statusText)
			}
		}
	}

	fmt.Fprintf(os.Stderr, "\nOverwriting will lose the newer local entries.\n\n")

	var confirmed bool
	form := huh.NewForm(
		huh.NewGroup(
			huh.NewConfirm().
				Title("Overwrite local session logs with checkpoint versions?").
				Value(&confirmed),
		),
	)
	if isAccessibleMode() {
		form = form.WithAccessible(true)
	}

	if err := form.Run(); err != nil {
		if errors.Is(err, huh.ErrUserAborted) {
			return false, nil
		}
		return false, fmt.Errorf("failed to get confirmation: %w", err)
	}

	return confirmed, nil
}

// Package checkpoint provides types and interfaces for checkpoint storage.
//
// A Checkpoint captures a point-in-time within a session, containing either
// full state (Temporary) or metadata with a commit reference (Committed).
//
// See docs/architecture/sessions-and-checkpoints.md for the full domain model.
package checkpoint

import (
	"context"
	"errors"
	"time"

	"github.com/entireio/cli/cmd/entire/cli/agent"
	"github.com/entireio/cli/cmd/entire/cli/checkpoint/id"

	"github.com/go-git/go-git/v5/plumbing"
)

// Errors returned by checkpoint operations.
var (
	// ErrCheckpointNotFound is returned when a checkpoint ID doesn't exist.
	ErrCheckpointNotFound = errors.New("checkpoint not found")

	// ErrNoTranscript is returned when a checkpoint exists but has no transcript.
	ErrNoTranscript = errors.New("no transcript found for checkpoint")
)

// Checkpoint represents a save point within a session.
type Checkpoint struct {
	// ID is the unique checkpoint identifier
	ID string

	// SessionID is the session this checkpoint belongs to
	SessionID string

	// Timestamp is when this checkpoint was created
	Timestamp time.Time

	// Type indicates temporary (full state) or committed (metadata only)
	Type Type

	// Message is a human-readable description of the checkpoint
	Message string
}

// Type indicates the storage location and lifecycle of a checkpoint.
type Type int

const (
	// Temporary checkpoints contain full state (code + metadata) and are stored
	// on shadow branches (entire/<commit-hash>). Used for intra-session rewind.
	Temporary Type = iota

	// Committed checkpoints contain metadata + commit reference and are stored
	// on the entire/checkpoints/v1 branch. They are the permanent record.
	Committed
)

// Store provides low-level primitives for reading and writing checkpoints.
// This is used by strategies to implement their storage approach.
//
// The interface matches the GitStore implementation signatures directly:
// - WriteTemporary takes WriteTemporaryOptions and returns a result with commit hash and skip status
// - ReadTemporary takes baseCommit (not sessionID) since shadow branches are keyed by commit
// - List methods return implementation-specific info types for richer data
type Store interface {
	// WriteTemporary writes a temporary checkpoint (full state) to a shadow branch.
	// Shadow branches are named entire/<base-commit-short-hash>.
	// Returns a result containing the commit hash and whether the checkpoint was skipped.
	// Checkpoints are skipped (deduplicated) when the tree hash matches the previous checkpoint.
	WriteTemporary(ctx context.Context, opts WriteTemporaryOptions) (WriteTemporaryResult, error)

	// ReadTemporary reads the latest checkpoint from a shadow branch.
	// baseCommit is the commit hash the session is based on.
	// worktreeID is the internal git worktree identifier (empty for main worktree).
	// Returns nil, nil if the shadow branch doesn't exist.
	ReadTemporary(ctx context.Context, baseCommit, worktreeID string) (*ReadTemporaryResult, error)

	// ListTemporary lists all shadow branches with their checkpoint info.
	ListTemporary(ctx context.Context) ([]TemporaryInfo, error)

	// WriteCommitted writes a committed checkpoint to the entire/checkpoints/v1 branch.
	// Checkpoints are stored at sharded paths: <id[:2]>/<id[2:]>/
	WriteCommitted(ctx context.Context, opts WriteCommittedOptions) error

	// ReadCommitted reads a committed checkpoint's summary by ID.
	// Returns only the CheckpointSummary (paths + aggregated stats), not actual content.
	// Use ReadSessionContent to read actual transcript/prompts/context.
	// Returns nil, nil if the checkpoint does not exist.
	ReadCommitted(ctx context.Context, checkpointID id.CheckpointID) (*CheckpointSummary, error)

	// ReadSessionContent reads the actual content for a specific session within a checkpoint.
	// sessionIndex is 0-based (0 for first session, 1 for second, etc.).
	// Returns the session's metadata, transcript, prompts, and context.
	ReadSessionContent(ctx context.Context, checkpointID id.CheckpointID, sessionIndex int) (*SessionContent, error)

	// ReadSessionContentByID reads a session's content by its session ID.
	// Useful when you have the session ID but don't know its index within the checkpoint.
	ReadSessionContentByID(ctx context.Context, checkpointID id.CheckpointID, sessionID string) (*SessionContent, error)

	// ListCommitted lists all committed checkpoints.
	ListCommitted(ctx context.Context) ([]CommittedInfo, error)

	// UpdateCommitted replaces the transcript, prompts, and context for an existing
	// committed checkpoint. Used at stop time to finalize checkpoints with the full
	// session transcript (prompt to stop event).
	// Returns ErrCheckpointNotFound if the checkpoint doesn't exist.
	UpdateCommitted(ctx context.Context, opts UpdateCommittedOptions) error
}

// WriteTemporaryResult contains the result of writing a temporary checkpoint.
type WriteTemporaryResult struct {
	// CommitHash is the hash of the created or existing checkpoint commit
	CommitHash plumbing.Hash

	// Skipped is true if the checkpoint was skipped due to no changes
	// (tree hash matched the previous checkpoint)
	Skipped bool
}

// WriteTemporaryOptions contains options for writing a temporary checkpoint.
type WriteTemporaryOptions struct {
	// SessionID is the session identifier
	SessionID string

	// BaseCommit is the commit hash this session is based on
	BaseCommit string

	// WorktreeID is the internal git worktree identifier (empty for main worktree)
	// Used to create worktree-specific shadow branch names
	WorktreeID string

	// ModifiedFiles are files that have been modified (relative paths)
	ModifiedFiles []string

	// NewFiles are files that have been created (relative paths)
	NewFiles []string

	// DeletedFiles are files that have been deleted (relative paths)
	DeletedFiles []string

	// MetadataDir is the relative path to the metadata directory
	MetadataDir string

	// MetadataDirAbs is the absolute path to the metadata directory
	MetadataDirAbs string

	// CommitMessage is the commit subject line
	CommitMessage string

	// AuthorName is the name to use for commits
	AuthorName string

	// AuthorEmail is the email to use for commits
	AuthorEmail string

	// IsFirstCheckpoint indicates if this is the first checkpoint of the session
	// When true, all working directory files are captured (not just modified)
	IsFirstCheckpoint bool
}

// ReadTemporaryResult contains the result of reading a temporary checkpoint.
type ReadTemporaryResult struct {
	// CommitHash is the hash of the checkpoint commit
	CommitHash plumbing.Hash

	// TreeHash is the hash of the tree containing the checkpoint state
	TreeHash plumbing.Hash

	// SessionID is the session identifier from the commit trailer
	SessionID string

	// MetadataDir is the metadata directory path from the commit trailer
	MetadataDir string

	// Timestamp is when the checkpoint was created
	Timestamp time.Time
}

// TemporaryInfo contains summary information about a shadow branch.
type TemporaryInfo struct {
	// BranchName is the full branch name (e.g., "entire/abc1234")
	BranchName string

	// BaseCommit is the short commit hash this branch is based on
	BaseCommit string

	// LatestCommit is the hash of the latest commit on the branch
	LatestCommit plumbing.Hash

	// SessionID is the session identifier from the latest commit
	SessionID string

	// Timestamp is when the latest checkpoint was created
	Timestamp time.Time
}

// WriteCommittedOptions contains options for writing a committed checkpoint.
type WriteCommittedOptions struct {
	// CheckpointID is the stable 12-hex-char identifier
	CheckpointID id.CheckpointID

	// SessionID is the session identifier
	SessionID string

	// Strategy is the name of the strategy that created this checkpoint
	Strategy string

	// Branch is the branch name where the checkpoint was created (empty if detached HEAD)
	Branch string

	// Transcript is the session transcript content (full.jsonl)
	Transcript []byte

	// Prompts contains user prompts from the session
	Prompts []string

	// Context is the generated context.md content
	Context []byte

	// FilesTouched are files modified during the session
	FilesTouched []string

	// CheckpointsCount is the number of checkpoints in this session
	CheckpointsCount int

	// EphemeralBranch is the shadow branch name (for manual-commit strategy)
	EphemeralBranch string

	// AuthorName is the name to use for commits
	AuthorName string

	// AuthorEmail is the email to use for commits
	AuthorEmail string

	// MetadataDir is a directory containing additional metadata files to copy
	// If set, all files in this directory will be copied to the checkpoint path
	// This is useful for copying task metadata files, subagent transcripts, etc.
	MetadataDir string

	// Task checkpoint fields (for auto-commit strategy task checkpoints)
	IsTask    bool   // Whether this is a task checkpoint
	ToolUseID string // Tool use ID for task checkpoints

	// Additional task checkpoint fields for subagent checkpoints
	AgentID                string // Subagent identifier
	CheckpointUUID         string // UUID for transcript truncation when rewinding
	TranscriptPath         string // Path to session transcript file (alternative to in-memory Transcript)
	SubagentTranscriptPath string // Path to subagent's transcript file

	// Incremental checkpoint fields
	IsIncremental       bool   // Whether this is an incremental checkpoint
	IncrementalSequence int    // Checkpoint sequence number
	IncrementalType     string // Tool type that triggered this checkpoint
	IncrementalData     []byte // Tool input payload for this checkpoint

	// Commit message fields (used for task checkpoints)
	CommitSubject string // Subject line for the metadata commit (overrides default)

	// Agent identifies the agent that created this checkpoint (e.g., "Claude Code", "Cursor")
	Agent agent.AgentType

	// TurnID correlates checkpoints from the same agent turn.
	TurnID string

	// Transcript position at checkpoint start - tracks what was added during this checkpoint
	TranscriptIdentifierAtStart string // Last identifier when checkpoint started (UUID for Claude, message ID for Gemini)
	CheckpointTranscriptStart   int    // Transcript line offset at start of this checkpoint's data

	// CheckpointTranscriptStart is written to both CommittedMetadata.CheckpointTranscriptStart
	// and the deprecated CommittedMetadata.TranscriptLinesAtStart for backward compatibility.

	// TokenUsage contains the token usage for this checkpoint
	TokenUsage *agent.TokenUsage

	// InitialAttribution is line-level attribution calculated at commit time
	// comparing checkpoint tree (agent work) to committed tree (may include human edits)
	InitialAttribution *InitialAttribution

	// Summary is an optional AI-generated summary for this checkpoint.
	// This field may be nil when:
	//   - summarization is disabled in settings
	//   - summary generation failed (non-blocking, logged as warning)
	//   - the transcript was empty or too short to summarize
	//   - the checkpoint predates the summarization feature
	Summary *Summary

	// SessionTranscriptPath is the home-relative path to the session transcript file.
	// Persisted in CommittedMetadata so restore can write the transcript back to
	// the correct location without reconstructing agent-specific paths.
	SessionTranscriptPath string
}

// UpdateCommittedOptions contains options for updating an existing committed checkpoint.
// Uses replace semantics: the transcript, prompts, and context are fully replaced,
// not appended. At stop time we have the complete session transcript and want every
// checkpoint to contain it identically.
type UpdateCommittedOptions struct {
	// CheckpointID identifies the checkpoint to update
	CheckpointID id.CheckpointID

	// SessionID identifies which session slot to update within the checkpoint
	SessionID string

	// Transcript is the full session transcript (replaces existing)
	Transcript []byte

	// Prompts contains all user prompts (replaces existing)
	Prompts []string

	// Context is the updated context.md content (replaces existing)
	Context []byte

	// Agent identifies the agent type (needed for transcript chunking)
	Agent agent.AgentType
}

// CommittedInfo contains summary information about a committed checkpoint.
type CommittedInfo struct {
	// CheckpointID is the stable 12-hex-char identifier
	CheckpointID id.CheckpointID

	// SessionID is the session identifier (most recent session for multi-session checkpoints)
	SessionID string

	// CreatedAt is when the checkpoint was created
	CreatedAt time.Time

	// CheckpointsCount is the total number of checkpoints across all sessions
	CheckpointsCount int

	// FilesTouched are files modified during all sessions
	FilesTouched []string

	// Agent identifies the agent that created this checkpoint
	Agent agent.AgentType

	// IsTask indicates if this is a task checkpoint
	IsTask bool

	// ToolUseID is the tool use ID for task checkpoints
	ToolUseID string

	// Multi-session support
	SessionCount int      // Number of sessions (1 if single session)
	SessionIDs   []string // All session IDs that contributed
}

// SessionContent contains the actual content for a session.
// This is used when reading full session data (transcript, prompts, context)
// as opposed to just the metadata/summary.
type SessionContent struct {
	// Metadata contains the session-specific metadata
	Metadata CommittedMetadata

	// Transcript is the session transcript content
	Transcript []byte

	// Prompts contains user prompts from this session
	Prompts string

	// Context is the context.md content
	Context string
}

// CommittedMetadata contains the metadata stored in metadata.json for each checkpoint.
type CommittedMetadata struct {
	CLIVersion       string          `json:"cli_version,omitempty"`
	CheckpointID     id.CheckpointID `json:"checkpoint_id"`
	SessionID        string          `json:"session_id"`
	Strategy         string          `json:"strategy"`
	CreatedAt        time.Time       `json:"created_at"`
	Branch           string          `json:"branch,omitempty"` // Branch where checkpoint was created (empty if detached HEAD)
	CheckpointsCount int             `json:"checkpoints_count"`
	FilesTouched     []string        `json:"files_touched"`

	// Agent identifies the agent that created this checkpoint (e.g., "Claude Code", "Cursor")
	Agent agent.AgentType `json:"agent,omitempty"`

	// TurnID correlates checkpoints from the same agent turn.
	// When a turn's work spans multiple commits, each gets its own checkpoint
	// but they share the same TurnID for future aggregation/deduplication.
	TurnID string `json:"turn_id,omitempty"`

	// Task checkpoint fields (only populated for task checkpoints)
	IsTask    bool   `json:"is_task,omitempty"`
	ToolUseID string `json:"tool_use_id,omitempty"`

	// Transcript position at checkpoint start - tracks what was added during this checkpoint
	TranscriptIdentifierAtStart string `json:"transcript_identifier_at_start,omitempty"` // Last identifier when checkpoint started (UUID for Claude, message ID for Gemini)
	CheckpointTranscriptStart   int    `json:"checkpoint_transcript_start,omitempty"`    // Transcript line offset at start of this checkpoint's data

	// Deprecated: Use CheckpointTranscriptStart instead. Written for backward compatibility with older CLI versions.
	TranscriptLinesAtStart int `json:"transcript_lines_at_start,omitempty"`

	// Token usage for this checkpoint
	TokenUsage *agent.TokenUsage `json:"token_usage,omitempty"`

	// AI-generated summary of the checkpoint
	Summary *Summary `json:"summary,omitempty"`

	// InitialAttribution is line-level attribution calculated at commit time
	InitialAttribution *InitialAttribution `json:"initial_attribution,omitempty"`

	// TranscriptPath is the home-relative path to the session transcript file.
	// Persisted so restore can write the transcript back to the correct location
	// without needing to reconstruct agent-specific paths (e.g. SHA-256 hashed dirs for Gemini).
	TranscriptPath string `json:"transcript_path,omitempty"`
}

// GetTranscriptStart returns the transcript line offset at which this checkpoint's data begins.
// Returns 0 for new checkpoints (start from beginning). For data written by older CLI versions,
// falls back to the deprecated TranscriptLinesAtStart field.
func (m CommittedMetadata) GetTranscriptStart() int {
	if m.CheckpointTranscriptStart > 0 {
		return m.CheckpointTranscriptStart
	}
	return m.TranscriptLinesAtStart
}

// SessionFilePaths contains the absolute paths to session files from the git tree root.
// Paths include the full checkpoint path prefix (e.g., "/a1/b2c3d4e5f6/1/metadata.json").
// Used in CheckpointSummary.Sessions to map session IDs to their file locations.
type SessionFilePaths struct {
	Metadata    string `json:"metadata"`
	Transcript  string `json:"transcript"`
	Context     string `json:"context"`
	ContentHash string `json:"content_hash"`
	Prompt      string `json:"prompt"`
}

// CheckpointSummary is the root-level metadata.json for a checkpoint.
// It contains aggregated statistics from all sessions and a map of session IDs
// to their file paths. Session-specific data (including initial_attribution)
// is stored in the session's subdirectory metadata.json.
//
// Structure on entire/checkpoints/v1 branch:
//
//	<checkpoint-id[:2]>/<checkpoint-id[2:]>/
//	├── metadata.json         # This CheckpointSummary
//	├── 1/                    # First session
//	│   ├── metadata.json     # Session-specific CommittedMetadata
//	│   ├── full.jsonl
//	│   ├── prompt.txt
//	│   ├── context.md
//	│   └── content_hash.txt
//	├── 2/                    # Second session
//	└── 3/                    # Third session...
//
//nolint:revive // Named CheckpointSummary to avoid conflict with existing Summary struct
type CheckpointSummary struct {
	CLIVersion       string             `json:"cli_version,omitempty"`
	CheckpointID     id.CheckpointID    `json:"checkpoint_id"`
	Strategy         string             `json:"strategy"`
	Branch           string             `json:"branch,omitempty"`
	CheckpointsCount int                `json:"checkpoints_count"`
	FilesTouched     []string           `json:"files_touched"`
	Sessions         []SessionFilePaths `json:"sessions"`
	TokenUsage       *agent.TokenUsage  `json:"token_usage,omitempty"`
}

// Summary contains AI-generated summary of a checkpoint.
type Summary struct {
	Intent    string           `json:"intent"`     // What user wanted to accomplish
	Outcome   string           `json:"outcome"`    // What was achieved
	Learnings LearningsSummary `json:"learnings"`  // Categorized learnings
	Friction  []string         `json:"friction"`   // Problems/annoyances encountered
	OpenItems []string         `json:"open_items"` // Tech debt, unfinished work
}

// LearningsSummary contains learnings grouped by scope.
type LearningsSummary struct {
	Repo     []string       `json:"repo"`     // Codebase-specific patterns/conventions
	Code     []CodeLearning `json:"code"`     // File/module specific findings
	Workflow []string       `json:"workflow"` // General dev practices
}

// CodeLearning captures a learning tied to a specific code location.
type CodeLearning struct {
	Path    string `json:"path"`               // File path
	Line    int    `json:"line,omitempty"`     // Start line number
	EndLine int    `json:"end_line,omitempty"` // End line for ranges (optional)
	Finding string `json:"finding"`            // What was learned
}

// InitialAttribution captures line-level attribution metrics at commit time.
// This is a point-in-time snapshot comparing the checkpoint tree (agent work)
// against the committed tree (may include human edits).
//
// Attribution Metrics:
//   - TotalCommitted measures "net additions" (lines added that remain in the commit)
//   - AgentPercentage represents "of the new code added, what percentage came from the agent"
//   - Deletion work is tracked separately in HumanRemoved (not included in percentage)
//
// Deletion-Only Commits:
// For commits with only deletions (no additions), TotalCommitted will be 0 and
// AgentPercentage will be 0. This is by design - the percentage metric is only
// meaningful for commits that add code. Deletion contributions are captured in
// the HumanRemoved field but don't affect the attribution percentage.
type InitialAttribution struct {
	CalculatedAt    time.Time `json:"calculated_at"`
	AgentLines      int       `json:"agent_lines"`      // Lines added by agent (base → shadow diff)
	HumanAdded      int       `json:"human_added"`      // Lines added by human (excluding modifications)
	HumanModified   int       `json:"human_modified"`   // Lines modified by human (estimate: min(added, removed))
	HumanRemoved    int       `json:"human_removed"`    // Lines removed by human (excluding modifications)
	TotalCommitted  int       `json:"total_committed"`  // Net additions in commit (agent + human new lines, not total file size)
	AgentPercentage float64   `json:"agent_percentage"` // agent_lines / total_committed * 100 (0 for deletion-only commits)
}

// Info provides summary information for listing checkpoints.
// This is the generic checkpoint info type.
type Info struct {
	// ID is the checkpoint identifier
	ID string

	// SessionID identifies the session
	SessionID string

	// Type indicates temporary or committed
	Type Type

	// CreatedAt is when the checkpoint was created
	CreatedAt time.Time

	// Message is a summary description
	Message string
}

// WriteTemporaryTaskOptions contains options for writing a task checkpoint.
// Task checkpoints are created when a subagent completes and contain both
// code changes and task-specific metadata.
type WriteTemporaryTaskOptions struct {
	// SessionID is the session identifier
	SessionID string

	// BaseCommit is the commit hash this session is based on
	BaseCommit string

	// WorktreeID is the internal git worktree identifier (empty for main worktree)
	// Used to create worktree-specific shadow branch names
	WorktreeID string

	// ToolUseID is the unique identifier for this Task tool invocation
	ToolUseID string

	// AgentID is the subagent identifier
	AgentID string

	// ModifiedFiles are files that have been modified (relative paths)
	ModifiedFiles []string

	// NewFiles are files that have been created (relative paths)
	NewFiles []string

	// DeletedFiles are files that have been deleted (relative paths)
	DeletedFiles []string

	// TranscriptPath is the path to the main session transcript
	TranscriptPath string

	// SubagentTranscriptPath is the path to the subagent's transcript
	SubagentTranscriptPath string

	// CheckpointUUID is the UUID for transcript truncation when rewinding
	CheckpointUUID string

	// CommitMessage is the commit message (already formatted)
	CommitMessage string

	// AuthorName is the name to use for commits
	AuthorName string

	// AuthorEmail is the email to use for commits
	AuthorEmail string

	// IsIncremental indicates this is an incremental checkpoint
	IsIncremental bool

	// IncrementalSequence is the checkpoint sequence number
	IncrementalSequence int

	// IncrementalType is the tool that triggered this checkpoint
	IncrementalType string

	// IncrementalData is the tool_input payload for this checkpoint
	IncrementalData []byte
}

// TemporaryCheckpointInfo contains information about a single commit on a shadow branch.
// Used by ListTemporaryCheckpoints to provide rewind point data.
type TemporaryCheckpointInfo struct {
	// CommitHash is the hash of the checkpoint commit
	CommitHash plumbing.Hash

	// Message is the first line of the commit message
	Message string

	// SessionID is the session identifier from the Entire-Session trailer
	SessionID string

	// MetadataDir is the metadata directory path from trailers
	MetadataDir string

	// IsTaskCheckpoint indicates if this is a task checkpoint
	IsTaskCheckpoint bool

	// ToolUseID is the tool use ID for task checkpoints
	ToolUseID string

	// Timestamp is when the checkpoint was created
	Timestamp time.Time
}

